<?php
namespace App\Domain\Inventory\Capacity;
use App\Domain\Inventory\Capacity\Data\InventorySlotResult;
use InvalidArgumentException;
final class InventorySlotCalculator{public function calculate(array $lines){$quantities=[];$maxStacks=[];foreach($lines as $line){foreach(['item_id','quantity','max_stack'] as $key)if(!array_key_exists($key,$line)||!is_int($line[$key]))throw new InvalidArgumentException('Inventory slot input must use safe PHP integers.');$id=$line['item_id'];$quantity=$line['quantity'];$max=$line['max_stack'];if($id<=0||$quantity<0||$max<=0)throw new InvalidArgumentException('Invalid inventory slot input.');$old=isset($quantities[$id])?$quantities[$id]:0;if($quantity>PHP_INT_MAX-$old)throw new InvalidArgumentException('Inventory quantity overflow.');if(isset($maxStacks[$id])&&$maxStacks[$id]!==$max)throw new InvalidArgumentException('Conflicting max stack.');$quantities[$id]=$old+$quantity;$maxStacks[$id]=$max;}$slots=0;foreach($quantities as $id=>$quantity){$itemSlots=intdiv($quantity,$maxStacks[$id])+($quantity%$maxStacks[$id]===0?0:1);if($itemSlots>PHP_INT_MAX-$slots)throw new InvalidArgumentException('Inventory slot overflow.');$slots+=$itemSlots;}return new InventorySlotResult($quantities,$slots);}}
